const body = $input.first().json.body;

// Filtrar: somente eventos messages.upsert
if (!body || body.event !== 'messages.upsert') {
  return [];
}

const data = body.data;

// Filtrar mensagens enviadas pelo proprio bot
if (data.key && data.key.fromMe) {
  return [];
}

// Filtrar mensagens de grupo (somente DM)
const remoteJid = data.key?.remoteJid || '';
if (remoteJid.includes('@g.us')) {
  return [];
}

// Extrair numero de telefone
const phone = remoteJid.replace('@s.whatsapp.net', '');

// Extrair texto da mensagem (diferentes formatos)
let messageText = '';
if (data.message?.conversation) {
  messageText = data.message.conversation;
} else if (data.message?.extendedTextMessage?.text) {
  messageText = data.message.extendedTextMessage.text;
} else {
  // Mensagem de midia (imagem, audio, video, etc.)
  return [{
    json: {
      phone,
      message: '',
      isMedia: true,
      remoteJid,
      pushName: data.pushName || 'Usuario'
    }
  }];
}

// Sanitizar: trim e limitar tamanho
messageText = messageText.trim().substring(0, 2000);

if (!messageText) {
  return [];
}

return [{
  json: {
    phone,
    message: messageText,
    isMedia: false,
    remoteJid,
    pushName: data.pushName || 'Usuario',
    timestamp: data.messageTimestamp
  }
}];

