const dataStr = $fromAI('data', 'JSON string with the data to process', 'string');
const operation = $fromAI('operation', 'Description of what calculation or formatting to perform', 'string');

let parsed;
try {
  parsed = JSON.parse(dataStr);
} catch (e) {
  return { error: 'JSON invalido', raw: dataStr };
}

// Helper: formatar BRL
const formatBRL = (value) => {
  if (typeof value !== 'number' || isNaN(value)) return 'N/A';
  return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value);
};

// Helper: formatar percentual
const formatPercent = (value) => {
  if (typeof value !== 'number' || isNaN(value)) return 'N/A';
  return `${(value * 100).toFixed(1)}%`;
};

// Processar array de dados
if (Array.isArray(parsed)) {
  const formatted = parsed.map(item => {
    const result = { ...item };
    for (const [key, value] of Object.entries(result)) {
      if (typeof value === 'number') {
        if (key.includes('faturamento') || key.includes('investimento') || key.includes('preco') || key.includes('ticket') || key.includes('ganho') || key.includes('meta')) {
          result[`${key}_formatado`] = formatBRL(value);
        }
      }
    }
    return result;
  });

  return {
    total_registros: formatted.length,
    operacao: operation,
    dados: formatted
  };
}

return {
  operacao: operation,
  dados: parsed
};

const agentOutput = $input.first().json.output || $input.first().json.text || 'Desculpe, nao consegui processar sua solicitacao. Tente novamente.';
const phone = $('Parse WhatsApp Message').first().json.phone;

// WhatsApp tem limite de ~4096 caracteres por mensagem
const MAX_LENGTH = 4000;
let responseText = agentOutput;

// Truncar se muito longo
if (responseText.length > MAX_LENGTH) {
  responseText = responseText.substring(0, MAX_LENGTH) + '\n\n_... resposta truncada por limite do WhatsApp_';
}

// Converter markdown para formato WhatsApp
// Headers ## → *bold*
responseText = responseText.replace(/#{1,6}\s+(.+)/g, '*$1*');
// **bold** → *bold* (WhatsApp usa asterisco simples)
responseText = responseText.replace(/\*\*(.+?)\*\*/g, '*$1*');
// Manter _italic_ (WhatsApp suporta)
// Manter ~strikethrough~ (WhatsApp suporta)
// ```code``` → manter (WhatsApp suporta)

return [{
  json: {
    phone,
    text: responseText
  }
}];
